challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is overloaded by a massive GTP-U traffic storm on the N3 interface, causing extreme packet loss for all user plane traffic, including RTP media for VoNR calls.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check status of all containers",
          "expected_if_hypothesis_holds": "The UPF container's CPU and memory utilization metrics are very high.",
          "falsifying_observation": "The UPF container's CPU and memory utilization are within normal limits.",
          "conflates_with": []
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: nr_gnb, to_ip: upf",
          "expected_if_hypothesis_holds": "High RTT and/or packet loss is observed.",
          "falsifying_observation": "RTT and packet loss are normal.",
          "conflates_with": [
            "The network path between the gNB and the UPF is degraded."
          ]
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: smf, to_ip: upf",
          "expected_if_hypothesis_holds": "High RTT and/or packet loss is observed, similar to the gNB->UPF path.",
          "falsifying_observation": "RTT and packet loss are normal, indicating the issue is specific to the N3 path or interface, not general UPF overload.",
          "conflates_with": []
        }
      ],
      "notes": "This plan tests the 'UPF overload' hypothesis by checking resource metrics directly and then uses a set of paired RTT probes to distinguish a general UPF failure from a path-specific one. This directly addresses the ambiguity noted in the linter feedback for compositional probes."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "A severe degradation on the N3 data path between the gNB and the UPF is causing widespread packet loss, impacting all user traffic.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check status of all containers",
          "expected_if_hypothesis_holds": "The UPF container's CPU and memory utilization metrics are within normal limits.",
          "falsifying_observation": "The UPF container's CPU and memory utilization metrics are very high, pointing towards UPF overload (h1) rather than path degradation.",
          "conflates_with": []
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: nr_gnb, to_ip: upf",
          "expected_if_hypothesis_holds": "High RTT and/or packet loss is observed.",
          "falsifying_observation": "RTT and packet loss are normal, which would falsify the claim of N3 path degradation.",
          "conflates_with": [
            "The UPF itself is overloaded."
          ]
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: smf, to_ip: upf",
          "expected_if_hypothesis_holds": "RTT and packet loss are normal, indicating the UPF itself is responsive on other interfaces.",
          "falsifying_observation": "High RTT and/or packet loss is observed, suggesting the problem is with the UPF itself (h1), not just the N3 path.",
          "conflates_with": []
        }
      ],
      "notes": "This plan is designed to differentiate between path degradation (h2) and UPF overload (h1). The probes are identical to the h1 plan, but the expected outcomes are inverted to test the alternative hypothesis. The paired RTT probes are essential for localizing the fault."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "The RTPEngine is the source of the observed media packet loss, indicating a fault within the RTPEngine itself.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check status of all containers",
          "expected_if_hypothesis_holds": "The RTPEngine container's CPU and memory utilization metrics are very high, or its internal error counters are increasing.",
          "falsifying_observation": "The RTPEngine container's resources are within normal limits and there are no new errors.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "The gauges show high packet loss and low MOS for RTP streams handled by RTPEngine.",
          "falsifying_observation": "The gauges show normal packet loss and MOS for RTP streams.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "The gauges for the UPF's N3 user plane traffic show volumes consistent with the number of ongoing calls.",
          "falsifying_observation": "The gauges for the UPF's N3 user plane traffic show anomalously high volume or a collapse to near-zero, which contradicts the fault being isolated to RTPEngine.",
          "conflates_with": []
        }
      ],
      "notes": "This plan directly investigates the health of RTPEngine and, crucially, checks for the contradictory evidence on the UPF that was mentioned in the NA report. The falsifying observation for the third probe is key to disproving this hypothesis in favor of a core network fault."
    }
  ]
}

